CREATE VIEW `dwd_flow_app_cdtiming_view` (`dt` COMMENT "分区日期", `id` COMMENT "nvl(rid,track_id)", `track_id`, `rid` COMMENT "记录ID", `event_tm` COMMENT "事件时间", `device_id` COMMENT "设备id", `login_id` COMMENT "登录用户id", `identity_login_id` COMMENT "identity_login_id", `device_lang` COMMENT "设备语言", `event` COMMENT "事件", `distinct_id` COMMENT "distinct_id(用户id)", `identity_user_id` COMMENT "identity_userid（用户id）", `product_id` COMMENT "包体ID", `corever` COMMENT "core", `mt` COMMENT "终端", `app_ver` COMMENT "app版本", `app_channel` COMMENT "渠道编号", `app_lang_id` COMMENT "界面语言", `serial` COMMENT "加载时长(ms)", `type` COMMENT "类型 7为页面加载时长8为接口加载时长", `position` COMMENT "页面位置", `channel_id` COMMENT "书城特定频道的上报", `cd_timing` COMMENT "CDTiming", `etl_tm` COMMENT "清洗时间")
